    def flood(r, c):
        cells = []
        stack = [(r, c)]
        while stack:
            cr, cc = stack.pop()
            if 0 <= cr < h and 0 <= cc < w and not visited[cr][cc] and grid[cr][cc] == 8:
                visited[cr][cc] = True
                cells.append((cr, cc))
                for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                    stack.append((cr+dr, cc+dc))
        return cells
    eight_groups = []
    for r in range(h):
        for c in range(w):
            if grid[r][c] == 8 and not visited[r][c]:
                eight_groups.append(flood(r, c))
    template_cells = [(r, c, grid[r][c]) for r in range(h) for c in range(w) if grid[r][c] != 0 and grid[r][c] != 8]
    template_norm = {}
    if template_cells:
        min_r = min(r for r, c, v in template_cells)
        min_c = min(c for r, c, v in template_cells)
        template_norm = {(r - min_r, c - min_c): v for r, c, v in template_cells}
    out = [[0]*w for _ in range(h)]
    for group in eight_groups:
        min_r = min(r for r, c in group)
        min_c = min(c for r, c in group)
        for r, c in group:
            dr, dc = r - min_r, c - min_c
            if (dr, dc) in template_norm:
                out[r][c] = template_norm[(dr, dc)]
    return out

