    def equivalents(r, c):
        positions = set()
        for rr, cc in [(r,c), (c,r), (31-r,c), (r,31-c), (31-r,31-c), (c,31-r), (31-c,r), (31-c,31-r)]:
            if 0 <= rr < n and 0 <= cc < n:
                positions.add((rr, cc))
        return positions
    changed = True
    while changed:
        changed = False
        for r in range(n):
            for c in range(n):
                if out[r][c] == 9:
                    for rr, cc in equivalents(r, c):
                        if out[rr][cc] != 9:
                            out[r][c] = out[rr][cc]
                            changed = True
                            break
    return out

