            r, c = queue.pop(0)
            for r2, c2 in list(remaining):
                if abs(r-r2) + abs(c-c2) <= 4:
                    cluster.add((r2, c2))
                    remaining.discard((r2, c2))
                    queue.append((r2, c2))
        clusters.append(cluster)

    all_crosses = []

    for cluster in clusters:
        row_twos = defaultdict(set)
        col_twos = defaultdict(set)
        for r, c in cluster:
            row_twos[r].add(c)
            col_twos[c].add(r)

