def solve(grid):
    import copy
    rows = len(grid)
    cols = len(grid[0])
    output = copy.deepcopy(grid)

    # Find all NxN all-zero blocks for N from large to small
    # Find the right block size and fill all non-overlapping instances
    for N in range(min(rows, cols), 1, -1):
        blocks = []
        for r1 in range(rows - N + 1):
            for c1 in range(cols - N + 1):
                all_zero = True
                for r in range(r1, r1+N):
                    for c in range(c1, c1+N):
                        if grid[r][c] != 0:
                            all_zero = False
                            break
                    if not all_zero:
                        break
                if all_zero:
                    blocks.append((r1, c1))
        if blocks:
            # Group overlapping blocks and take one representative per group
            def overlaps(b1, b2):
                r1, c1 = b1
                r2, c2 = b2
                return not (r1+N <= r2 or r2+N <= r1 or c1+N <= c2 or c2+N <= c1)
            groups = []
            for b in blocks:
                merged = False
                for g in groups:
                    if any(overlaps(b, gb) for gb in g):
                        g.append(b)
                        merged = True
                        break
                if not merged:
                    groups.append([b])
            reps = []
            for g in groups:
                g.sort()
                reps.append(g[0])
            for r1, c1 in reps:
                for r in range(r1, r1+N):
                    for c in range(c1, c1+N):
                        output[r][c] = 1
            return output
    return output

