                visited[r][c] = True
                while q:
                    cr2, cc2 = q.popleft()
                    comp.append((cr2, cc2))
                    for dr, dc in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
                        nr, nc = cr2 + dr, cc2 + dc
